export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(([x, y]) => coordKey(x, y)));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = coordKey(nx, ny);
      const existing = neighborCounts.get(k);
      if (existing) existing.count += 1;
      else neighborCounts.set(k, { cell: [nx, ny], count: 1 });
    }
  }

  const survives = (key: string, count: number): boolean =>
    count === 3 || (count === 2 && liveKeys.has(key));

  const result: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    if (survives(k, count)) result.push(cell);
  }
  return result;
}

