type NeighborTally = Map<string, { cell: Cell; count: number }>;

const tallyNeighbors = (cells: Cell[]): NeighborTally => {
  const tally: NeighborTally = new Map();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = coordKey(neighbor[0], neighbor[1]);
      const existing = tally.get(key);
      if (existing) existing.count += 1;
      else tally.set(key, { cell: neighbor, count: 1 });
    }
  }
  return tally;
};

const isAlive = (key: string, count: number, liveKeys: Set<string>): boolean =>
  count === 3 || (count === 2 && liveKeys.has(key));

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(([x, y]) => coordKey(x, y)));
  const result: Cell[] = [];
  for (const [key, { cell, count }] of tallyNeighbors(cells)) {
    if (isAlive(key, count, liveKeys)) result.push(cell);
  }
  return result;
}

